SELECT ?prop (COUNT(*) AS ?count) WHERE {
  VALUES ?dep {
    <http://api.koneksys.com/cameo/TMT/dependency/_18_0_2_b4c02e1_1443122846698_699746_180578>
  }
  ?dep ?prop ?value .
}
GROUP BY ?prop
ORDER BY DESC(?count)
